where 1 = 1




       and tpri.group_id = #{criteria.groupId,jdbcType=BIGINT}




       and tpri.enabled_flag = #{criteria.enabledFlag,jdbcType=BIT}




       and tpri.plan_id = #{criteria.planId,jdbcType=BIGINT}




       and tpri.check_method = #{criteria.checkMethod,jdbcType=VARCHAR}

mapper.insert:
insert into td_plan_result_interface (work_card, plan_id, attendance, duration, grade, evaluate, need_flag, enabled_flag, employee_id, operation_code, error_msg, data_status, group_id, name, create_time, create_by, update_time, update_by, score_line, match_implement_flag, remarks, check_method)
select case when #{workCard,jdbcType=VARCHAR} is null then null else right(cast('000000'+rtrim(#{workCard,jdbcType=VARCHAR}) as varchar),6) end , #{planId, jdbcType = BIGINT}, #{attendance, jdbcType = VARCHAR}, #{duration, jdbcType = DOUBLE}, #{grade, jdbcType = DOUBLE}, #{evaluate, jdbcType = DOUBLE}, #{needFlag, jdbcType = BIT}, 1, isnull((select pe.id from pm_employee pe where right(cast('000000'+rtrim(pe.work_card) as varchar),6) = right(cast('000000'+rtrim(#{workCard,jdbcType=VARCHAR}) as varchar),6) and pe.enabled_flag = 1 and pe.leave_flag = 0 ), -1), 'C', '', 'T', #{groupId, jdbcType = BIGINT}, #{name, jdbcType = VARCHAR}, getdate(), #{createBy, jdbcType= BIGINT}, getdate(), #{updateBy, jdbcType = BIGINT}, #{scoreLine, jdbcType = DOUBLE},
case when isnull((select pe.id from pm_employee pe where right(cast('000000'+rtrim(pe.work_card) as varchar),6) = right(cast('000000'+rtrim(#{workCard,jdbcType=VARCHAR}) as varchar),6) and pe.enabled_flag = 1 and pe.leave_flag = 0 ), -1) = -1 then 0 else case when exists (select tpe.employee_id from td_plan_employee tpe join td_plan_implement tpi on tpe.plan_implement_id = tpi.id and tpi.plan_id = #{planId, jdbcType = BIGINT} and tpe.enabled_flag = 1 and tpe.type = 'employee' and tpi.enabled_flag = 1 and tpi.approval_status = '已完成' join pm_employee pe on tpe.employee_id = pe.id and pe.enabled_flag = 1 and pe.leave_flag = 0 and right(cast('000000'+rtrim(pe.work_card) as varchar),6) = right(cast('000000'+rtrim(#{workCard,jdbcType=VARCHAR}) as varchar),6) ) then 1 else 0 end end, #{remarks, jdbcType = VARCHAR}, #{checkMethod, jdbcType = VARCHAR}
